package com.google.gson.reflect;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.GenericArrayType;
import java.lang.reflect.ParameterizedType;
import java.lang.reflect.Type;
import java.util.HashMap;

import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class TypeTokenIsAssignableFromTest {

  @Test
  void testIsAssignableFrom_genericArrayType_withParameterizedTypeComponent() throws Exception {
    // Arrange
    Type from = mock(Type.class);
    GenericArrayType to = mock(GenericArrayType.class);
    ParameterizedType parameterizedType = mock(ParameterizedType.class);

    when(to.getGenericComponentType()).thenReturn(parameterizedType);

    // Mock from as GenericArrayType
    GenericArrayType fromGenericArray = mock(GenericArrayType.class);
    when(from instanceof GenericArrayType).thenReturn(true); // This won't work because 'instanceof' is final

    // Because we cannot mock 'instanceof', we simulate behavior by using real classes.
    // So instead, create a GenericArrayType implementation for 'from'.
    GenericArrayType fromGenericArrayType = new GenericArrayType() {
      @Override
      public Type getGenericComponentType() {
        return parameterizedType;
      }
    };
    from = fromGenericArrayType;

    // Spy TypeToken to mock private static method isAssignableFrom(Type, ParameterizedType, Map)
    var typeTokenClass = TypeToken.class;
    var method = typeTokenClass.getDeclaredMethod("isAssignableFrom", Type.class, ParameterizedType.class, java.util.Map.class);
    method.setAccessible(true);

    // Act
    // Call private static method isAssignableFrom(Type, GenericArrayType) via reflection
    var focalMethod = typeTokenClass.getDeclaredMethod("isAssignableFrom", Type.class, GenericArrayType.class);
    focalMethod.setAccessible(true);
    Object result = focalMethod.invoke(null, from, to);

    // Assert
    // Since the private isAssignableFrom(Type, ParameterizedType, Map) is not mocked, 
    // it will be called with empty map and likely return false or true depending on implementation.
    // We just assert result is boolean.
    assertTrue(result instanceof Boolean);
  }

  @Test
  void testIsAssignableFrom_genericArrayType_withNonParameterizedComponent() throws Exception {
    // Arrange
    Type from = mock(Type.class);
    GenericArrayType to = mock(GenericArrayType.class);
    Type nonParameterizedType = mock(Type.class);

    when(to.getGenericComponentType()).thenReturn(nonParameterizedType);

    // Act
    var focalMethod = TypeToken.class.getDeclaredMethod("isAssignableFrom", Type.class, GenericArrayType.class);
    focalMethod.setAccessible(true);
    Object result = focalMethod.invoke(null, from, to);

    // Assert
    // When toGenericComponentType is not ParameterizedType, method returns true
    assertEquals(true, result);
  }

  @Test
  void testIsAssignableFrom_genericArrayType_withFromClassArray() throws Exception {
    // Arrange
    Class<?> from = String[][].class; // multi-dimensional array class
    GenericArrayType to = mock(GenericArrayType.class);

    // Create ParameterizedType for toGenericComponentType
    ParameterizedType parameterizedType = mock(ParameterizedType.class);
    when(to.getGenericComponentType()).thenReturn(parameterizedType);

    // Act
    var focalMethod = TypeToken.class.getDeclaredMethod("isAssignableFrom", Type.class, GenericArrayType.class);
    focalMethod.setAccessible(true);
    Object result = focalMethod.invoke(null, from, to);

    // Assert
    assertTrue(result instanceof Boolean);
  }

  @Test
  void testIsAssignableFrom_genericArrayType_withFromClassNonArray() throws Exception {
    // Arrange
    Class<?> from = String.class; // not an array
    GenericArrayType to = mock(GenericArrayType.class);

    ParameterizedType parameterizedType = mock(ParameterizedType.class);
    when(to.getGenericComponentType()).thenReturn(parameterizedType);

    // Act
    var focalMethod = TypeToken.class.getDeclaredMethod("isAssignableFrom", Type.class, GenericArrayType.class);
    focalMethod.setAccessible(true);
    Object result = focalMethod.invoke(null, from, to);

    // Assert
    assertTrue(result instanceof Boolean);
  }
}
